return [{
  "rowIndex": 3,
  "sheetRowId": "QPC-002",
  "headline": "In the quantum realm, electrons can 'see' a magnetic field even where the field itself is zero. This phenomenon, known as the Aharonov-Bohm effect, proves that potentials, not just forces, shape physical reality.",
  "topic": "Aharonov-Bohm",
  "highlights": ["quantum", "Aharonov-Bohm", "potentials", "reality"],
  "bg_image_url": "https://d1q70pf5vjeyhc.cloudfront.net/predictions/16d9857c2859415f997d85df0c81502c/1.jpeg",
  "facebook_caption": "In the quantum realm, reality behaves in ways that challenge our standard intuition. The Aharonov Bohm effect demonstrates that electrons can detect a magnetic field even if they never physically enter the region where that field exists. This discovery shifted our understanding of physics by proving that electromagnetic potentials are more than just mathematical tools. They are physical realities that can influence particles from a distance. By observing these subtle shifts in electron paths, scientists have confirmed the non local nature of the quantum world.",
  "linkedin_caption": "The Aharonov Bohm effect represents a fundamental milestone in quantum mechanics and electromagnetic theory. It illustrates that charged particles are sensitive to the magnetic vector potential even in regions where the magnetic field strength is zero. For professionals in research and technology, this underscores the profound importance of quantum phase shifts in designing precise instrumentation. This phenomenon confirms that the physical state of a system can be altered by potentials that exert no direct classical force. Understanding these mechanisms is essential for the future of quantum computing and advanced electron interferometry."
}];

// Test payload — skips Generate + Poll, goes straight to Extract Image URL.
// imageUrl = final image from Wavespeed. All other fields feed downstream nodes.
return [{
  imageUrl: "https://d2p7pge43lyniu.cloudfront.net/output/98e726ea-9107-4932-acbf-82fee64543ab.jpeg",
  headline: "In the quantum realm, electrons can detect a magnetic field even where the field itself is zero — proving that potentials, not forces, shape physical reality.",
  topic: "Aharonov-Bohm",
  highlights: ["Aharonov-Bohm", "quantum", "electromagnetic potentials", "electron", "interference"],
  image_search_query: "Aharonov-Bohm effect electron interference quantum physics",
  rowIndex: 2,
  sheetRowId: "QPC-001"
}];

const rows = $input.item.json?.values || [];
// Columns: 0=ID, 1=Topic, 2=CustomHeadline, 3=Status
const pending = rows
  .map((r, i) => ({ rowIndex: i + 2, id: r[0]||'', topic: r[1]||'', customHeadline: r[2]||'', status: (r[3]||'').toUpperCase().trim() }))
  .filter(r => r.status === 'PENDING' && r.topic);
if (pending.length === 0) {
  throw new Error('NO_PENDING_TOPICS: No PENDING topics found in Image Post Queue.');
}
const first = pending[0];
return [{ json: { rowIndex: first.rowIndex, sheetRowId: first.id, topic: first.topic, customHeadline: first.customHeadline } }];

const factData = $('Find First Pending Topic').item.json;
const topic = factData.customHeadline || factData.topic;
const prompt = `Generate one mind-blowing lesser-known quantum physics or particle physics fact about this topic: "${topic}"

Return ONLY valid JSON (no markdown, no code fences):
{
  "headline": "A mind-blowing fact in exactly 1 punchy sentence. STRICT word count: minimum 17 words, maximum 20 words — count carefully, never go below 17 or above 20.",
  "topic": "one-word physics concept",
  "highlights": ["Pick 3-5 single words that appear VERBATIM in the headline above and are the most important physics concepts. Only exact words from the headline — no phrases, no words not in the headline."],
  "image_search_query": "specific visual search query for a real photo"
}`;
return [{ json: { claude_payload: {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  messages: [{ role: 'user', content: prompt }]
} } }];

function parseClaudeJSON(raw) {
  const text = raw.trim().replace(/^```jsons*/i, "").replace(/^```s*/i, "").replace(/```s*$/i, "").trim();
  return JSON.parse(text);
}
const res = parseClaudeJSON($input.item.json.content[0].text);
const sheet = $('Find First Pending Topic').item.json;
// Spread res first so Claude fields are set, then sheet data wins — prevents Claude from overwriting rowIndex/sheetRowId
return [{ json: { ...res, rowIndex: sheet.rowIndex, sheetRowId: sheet.sheetRowId, topic: res.topic || sheet.topic, customHeadline: sheet.customHeadline } }];

function parseClaudeJSON(raw) {
  const text = raw.trim().replace(/^```jsons*/i, "").replace(/^```s*/i, "").replace(/```s*$/i, "").trim();
  return JSON.parse(text);
}
const res = parseClaudeJSON($input.item.json.content[0].text);
return [{ json: {
  prompt: res.visual_prompt,
  aspect_ratio: '4:5',
  negative_prompt: 'text, logo, watermark, blurry, low quality, distorted, cartoon'
} }];

const init = $input.item.json;
const pollUrl = init?.data?.urls?.get;
if (!pollUrl) throw new Error('No poll URL in Wavespeed response: ' + JSON.stringify(init));

const apiKey = $env.WAVESPEED_API_KEY;
const sleep = ms => new Promise(r => setTimeout(r, ms));

let attempts = 0;
let lastResp = null;
while (attempts < 40) {
  await sleep(5000);
  attempts++;
  try {
    lastResp = await this.helpers.httpRequest({
      method: 'GET',
      url: pollUrl,
      headers: { Authorization: 'Bearer ' + apiKey }
    });
  } catch(e) {
    throw new Error('Poll HTTP error on attempt ' + attempts + ': ' + e.message);
  }
  const d = lastResp?.data;
  const status = d?.status;
  const outputs = d?.outputs || [];
  // succeeded or completed with image
  if ((status === 'succeeded' || status === 'completed') && outputs.length > 0) {
    return [{ json: { imageUrl: outputs[0] } }];
  }
  // job expired or not found
  if (lastResp?.code !== 200 || status === 'failed') {
    throw new Error('Wavespeed job error (attempt ' + attempts + '): status=' + status + ' | response=' + JSON.stringify(lastResp).slice(0, 400));
  }
}
throw new Error('Wavespeed timed out after 40 polls. Last response: ' + JSON.stringify(lastResp).slice(0, 400));

const input = $input.item.json;
const imageUrl = input.imageUrl;
if (!imageUrl) throw new Error('No image URL: ' + JSON.stringify(input));
// If coming from Poll node, grab fact data from Parse Fact; if from Test payload, it's already in input
let factData = {};
try { factData = $('Parse Fact').item.json; } catch(e) {}
// input fields take priority when Poll path sets them; test payload has them directly
const merged = { ...factData, ...input };
delete merged.imageUrl;
return [{ json: { ...merged, bg_image_url: imageUrl } }];

const res = $input.item.json;
const images = res?.images || [];
const url = images.find(u => /\.(jpg|jpeg|png)/i.test(u)) || images[0] || '';
return [{ json: { ...($('Extract Image URL').item.json), ref_image_url: url } }];

function parseClaudeJSON(raw) {
  const text = raw.trim().replace(/^```jsons*/i, "").replace(/^```s*/i, "").replace(/```s*$/i, "").trim();
  return JSON.parse(text);
}
const res = parseClaudeJSON($input.item.json.content[0].text);
return [{ json: { ...($('Extract Image URL').item.json), ...res } }];

const fs = require('fs');
const https = require('https');
const http = require('http');

const downloadToFile = (url, dest) => new Promise((resolve, reject) => {
  const lib = url.startsWith('https') ? https : http;
  const file = fs.createWriteStream(dest);
  lib.get(url, res => {
    if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
      file.close();
      return downloadToFile(res.headers.location, dest).then(resolve).catch(reject);
    }
    res.pipe(file);
    file.on('finish', () => file.close(resolve));
    file.on('error', reject);
  }).on('error', reject);
});

const jobId = Date.now();
const bgN8n  = `/data/manim/scripts/qpc_bg_${jobId}.jpg`;
const refN8n = `/data/manim/scripts/qpc_ref_${jobId}.jpg`;
const outN8n = `/data/manim/renders/qpc_out_${jobId}.png`;
const bgMnm  = bgN8n.replace('/data/manim/scripts/','/manim/scripts/');
const refMnm = refN8n.replace('/data/manim/scripts/','/manim/scripts/');
const outMnm = outN8n.replace('/data/manim/renders/','/manim/renders/');

const factData = $input.item.json;

await downloadToFile(factData.bg_image_url, bgN8n);

let hasRef = false;
try {
  const refUrl = $('Extract Reference URL').item.json.ref_image_url;
  if (refUrl) {
    await downloadToFile(refUrl, refN8n);
    if (fs.statSync(refN8n).size > 1000) hasRef = true;
  }
} catch(e) {}

const config = JSON.stringify({
  bg_path:     bgMnm,
  ref_path:    hasRef ? refMnm : '',
  output_path: outMnm,
  headline:    factData.headline,
  highlights:  factData.highlights || []
});
return [{ json: {
  config, jobId, outN8n,
  rowIndex:          factData.rowIndex,
  sheetRowId:        factData.sheetRowId,
  headline:          factData.headline,
  facebook_caption:  factData.facebook_caption,
  linkedin_caption:  factData.linkedin_caption,
  instagram_caption: factData.instagram_caption,
  tiktok_caption:    factData.tiktok_caption
} }];

const { execSync, spawnSync } = require('child_process');
const config = $input.item.json.config;
const ts = Date.now();
const tmpCfg = '/tmp/qpc_cfg_' + ts + '.json';

// Write config via stdin — avoids all shell quoting issues (single quotes, etc.)
const write = spawnSync('docker', ['exec', '-i', 'qpc_manim_runner', 'bash', '-c', 'cat > ' + tmpCfg],
  { input: config, encoding: 'utf-8', timeout: 10000 });
if (write.status !== 0) throw new Error('Failed to write config: ' + (write.stderr || ''));

try {
  const stdout = execSync('docker exec qpc_manim_runner python3 /manim/scripts/composite_physics_post.py ' + tmpCfg,
    { encoding: 'utf-8', timeout: 300000 });
  execSync('docker exec qpc_manim_runner rm -f ' + tmpCfg, { timeout: 5000 });
  return [{ json: { ...$input.item.json, compositor_stdout: stdout.toString() } }];
} catch (e) {
  throw new Error('Compositor failed: ' + (e.stdout || e.message));
}

const fs = require('fs');
const outPath = $('Write Images to Volume').item.json.outN8n;
if (!fs.existsSync(outPath)) throw new Error('Output not found: ' + outPath);
const buf = fs.readFileSync(outPath);
const binary = await this.helpers.prepareBinaryData(buf, 'physics_post.png', 'image/png');
const d = $('Write Images to Volume').item.json;
const now = new Date().toISOString().slice(0,10);
return [{ json: {
  fileName:          `schrodingers_cat_${now}_${d.jobId}.png`,
  rowIndex:          d.rowIndex,
  sheetRowId:        d.sheetRowId,
  headline:          d.headline,
  facebook_caption:  d.facebook_caption,
  linkedin_caption:  d.linkedin_caption,
  instagram_caption: d.instagram_caption,
  tiktok_caption:    d.tiktok_caption
}, binary: { data: binary } }];

const drive = $input.item.json;
const prev  = $('Read Output Image').item.json;
return [{ json: {
  ...prev,
  drive_file_id: drive.id,
  drive_url:     `https://drive.usercontent.google.com/download?id=${drive.id}&export=download&confirm=t`
} }];

const res = $input.item.json;
const fb_post_id  = res?.fb_post_id  || '';
const li_post_id  = res?.li_post_id  || '';
const driveFileId = res?.drive_file_id || '';
const driveUrl    = res?.drive_url    || '';
const headline    = $('Read Output Image').item.json.headline;
const rowIndex    = $('Read Output Image').item.json.rowIndex;
const now = new Date().toISOString();
return [{ json: { rowIndex, fb_post_id, li_post_id, driveFileId, driveUrl, headline, publishedAt: now } }];

const d = $('Read Output Image').item.json;
const drive = $('Upload to Google Drive').item.json;
return [{ json: {
  headline:          d.headline,
  facebook_caption:  d.facebook_caption,
  linkedin_caption:  d.linkedin_caption,
  instagram_caption: d.instagram_caption,
  tiktok_caption:    d.tiktok_caption,
  drive_file_id:     drive.id,
  drive_url:        `https://drive.usercontent.google.com/download?id=${drive.id}&export=download&confirm=t`,
  rowIndex:         d.rowIndex
} }];
